class Solution:
    def maxProfit(self, prices):
        from functools import lru_cache
        n = len(prices)
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(maxsize=None)
        def go(i, holding):
            if i == n:
                return 0
            best = go(i + 1, holding)
            if holding:
                best = max(best, prices[i] + go(i + 1, False))
            else:
                best = max(best, -prices[i] + go(i + 1, True))
            return best
        return go(0, False)

